// Regenerates src/scanner/fingerprint/sniffypedia.generated.ts from the
// reelyActive Sniffypedia index, which maps BLE 16-bit member service UUIDs to
// the product or organization they belong to.
//
// Sniffypedia is © reelyActive, made available under the Open Database License
// (ODbL 1.0); individual contents under CC BY-SA 4.0. Keep the attribution in
// the generated file.
//
//   node scripts/generate-sniffypedia.mjs
//
// Commit the regenerated file.
import { writeFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

const SOURCE =
  'https://raw.githubusercontent.com/reelyactive/sniffypedia/master/lib/bluetoothlowenergy.js';
const OUT = join(
  dirname(fileURLToPath(import.meta.url)),
  '..',
  'src',
  'scanner',
  'fingerprint',
  'sniffypedia.generated.ts'
);

// Trailing legal-form tokens that add noise to evidence labels.
const LEGAL_SUFFIXES = new Set([
  'Inc',
  'Ltd',
  'LLC',
  'Corporation',
  'Corp',
  'GmbH',
  'SA',
  'AB',
  'AG',
  'BV',
  'Oy',
  'ASA',
  'Co',
  'Limited',
  'Services',
  'Holdings',
  'International',
  'Innovations',
  'Technologies',
  'Communications',
  'com',
]);

// "/Product/Tile_Tile/" → "Tile", "/Organization/Ruuvi_Innovations_Ltd/" → "Ruuvi".
function labelFromUri(uri) {
  const segment = uri.split('/').filter(Boolean).pop();
  let words = segment.split('_').filter(Boolean);
  while (words.length > 1 && LEGAL_SUFFIXES.has(words[words.length - 1])) words.pop();
  // Collapse immediate duplicate words ("Tile Tile" → "Tile").
  words = words.filter((word, index) => word.toLowerCase() !== words[index - 1]?.toLowerCase());
  return words.join(' ');
}

function parseTable(source, tableName) {
  const start = source.indexOf(`const ${tableName} = {`);
  if (start === -1) throw new Error(`Table ${tableName} not found — source format changed.`);
  const body = source.slice(start, source.indexOf('};', start));
  const entries = [];
  for (const match of body.matchAll(/"([0-9a-f]{4})":\s*"([^"]+)"/g)) {
    entries.push([match[1], match[2]]);
  }
  return entries;
}

const res = await fetch(SOURCE);
if (!res.ok) throw new Error(`Failed to fetch ${SOURCE}: ${res.status}`);
const source = await res.text();

const products = [];
const orgs = [];
for (const [uuid, uri] of parseTable(source, 'UUID16')) {
  if (uri.startsWith('/Product/')) products.push([uuid, labelFromUri(uri)]);
  else if (uri.startsWith('/Organization/')) orgs.push([uuid, labelFromUri(uri)]);
}
if (products.length < 4 || orgs.length < 50) {
  throw new Error(
    `Parsed only ${products.length} products / ${orgs.length} orgs — source format likely changed.`
  );
}

const toLines = (entries) =>
  entries
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([uuid, label]) => `  '${uuid}': ${JSON.stringify(label)},`)
    .join('\n');

const contents = `// AUTO-GENERATED by scripts/generate-sniffypedia.mjs — DO NOT EDIT BY HAND.
// Source: reelyactive/sniffypedia (https://sniffypedia.org), © reelyActive,
// Open Database License (ODbL 1.0), contents CC BY-SA 4.0.
// Regenerate with: node scripts/generate-sniffypedia.mjs

// BLE member service UUIDs (16-bit, lowercase hex) that identify a specific
// product line (e.g. fe ed → Tile).
export const SNIFFYPEDIA_UUID16_PRODUCTS: Record<string, string> = {
${toLines(products)}
};

// BLE member service UUIDs that identify the organization that registered
// them — weaker than a product match but still narrows the device down.
export const SNIFFYPEDIA_UUID16_ORGS: Record<string, string> = {
${toLines(orgs)}
};
`;

writeFileSync(OUT, contents);
console.log(`Wrote ${OUT}: ${products.length} products, ${orgs.length} organizations.`);
